# ruff: noqa: T201
"""Runner script to generate the Bynder DataSource wrapper.

Execute this script to regenerate bynder.py from the method definitions
in code_generator.py.

Usage:
    python -m app.sources.external.bynder.run_generator
"""

from app.sources.external.bynder.code_generator import generate_datasource


def main() -> None:
    """Generate the Bynder DataSource file."""
    code = generate_datasource()
    output_path = __file__.replace("run_generator.py", "bynder.py")
    with open(output_path, "w") as f:
        f.write(code)
    print(f"Generated Bynder DataSource -> {output_path}")
    print(f"  Total characters: {len(code)}")


if __name__ == "__main__":
    main()
